use std::collections::HashMap;

struct Student {
    name: String,
    grades: Vec<f64>,
}

impl Student {
    fn new(name: &str) -> Student {
        Student {
            name: name.to_string(),
            grades: Vec::new(),
        }
    }

    fn add_grade(&mut self, grade: f64) {
        self.grades.push(grade);
    }

    fn average(&self) -> f64 {
        if self.grades.is_empty() {
            return 0.0;
        }
        let sum: f64 = self.grades.iter().sum();
        sum / self.grades.len() as f64
    }

    fn highest(&self) -> f64 {
        self.grades.iter().cloned().fold(f64::MIN, f64::max)
    }
}

fn class_report(students: &[Student]) {
    let mut class_avg = 0.0;
    for s in students {
        let avg = s.average();
        println!("{}: avg={:.1}, highest={:.1}", s.name, avg, s.highest());
        class_avg += avg;
    }
    class_avg /= students.len() as f64;
    println!("Class average: {:.1}", class_avg);
}

fn main() {
    let mut students = vec![
        Student::new("Alice"),
        Student::new("Bob"),
        Student::new("Charlie"),
    ];

    students[0].add_grade(92.0);
